import { type ReactNode } from 'react';

import { Tooltip, TooltipTrigger } from './base/tooltip';

export type ConditionalTooltipProps = {
  /** Content rendered inside the tooltip when shown. */
  text: string | ReactNode;
  /** When `true`, wraps `children` in a tooltip; when `false`, renders them as-is. */
  isTruncated: boolean;
  /** The element that becomes the tooltip trigger when truncated. */
  children: ReactNode;
};

/**
 * Wraps `children` in a tooltip only when the consumer has detected truncation.
 * Pair with `useTruncation()` from `@/hooks/use-truncation`.
 */
export function ConditionalTooltip({
  text,
  isTruncated,
  children,
}: ConditionalTooltipProps) {
  if (!isTruncated) return <>{children}</>;

  return (
    <Tooltip
      title={text}
      placement="top"
    >
      <TooltipTrigger
        isDisabled={false}
        className="flex w-full min-w-0 cursor-default text-left"
      >
        {children}
      </TooltipTrigger>
    </Tooltip>
  );
}
